            bvQuarterRound(state, 3, 7, 11, 15)
            bvQuarterRound(state, 4, 8, 12, 16)
            bvQuarterRound(state, 1, 6, 11, 16)
            bvQuarterRound(state, 2, 7, 12, 13)
            bvQuarterRound(state, 3, 8, 9, 14)
            bvQuarterRound(state, 4, 5, 10, 15)
